:root {
  --bg-card: #ffffff;
  --border-card: #e8e8e8;
  --header-bg: #1a1a2e;
  --header-text: #ffffff;
  --subtitle-text: #a0a8c0;
  --icon-bg: #2d2d4e;

  --pill-interview-bg: #2563eb;
  --pill-interview-text: #ffffff;
  --pill-offer-bg: #16a34a;
  --pill-offer-text: #ffffff;

  --row-border: #f0f0f0;
  --company-text: #1a1a2e;
  --role-text: #6b7280;
  --date-text: #9ca3af;

  --bar-offer: #16a34a;
  --bar-interview: #2563eb;
  --bar-applied: #f59e0b;
  --bar-rejected: #ef4444;

  --badge-offer-bg: #dcfce7;
  --badge-offer-text: #15803d;
  --badge-interview-bg: #dbeafe;
  --badge-interview-text: #1d4ed8;
  --badge-applied-bg: #fef3c7;
  --badge-applied-text: #b45309;
  --badge-rejected-bg: #fee2e2;
  --badge-rejected-text: #dc2626;

  --progress-track-bg: #f3f4f6;
  --progress-fill-bg: #2563eb;
  --progress-label-text: #374151;
  --progress-pct-text: #2563eb;
}

.tracker {
  width: 500px;
  background: var(--bg-card);
  border: 1px solid var(--border-card);
  border-radius: 16px;
  overflow: hidden;
  margin: 0 auto;
}

.tracker-header {
  background: var(--header-bg);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.header-icon {
  width: 40px;
  height: 40px;
  background: var(--icon-bg);
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
}

.tracker-title {
  font-size: 18px;
  font-weight: 700;
  color: var(--header-text);
  margin: 0;
  line-height: 1.2;
}

.tracker-subtitle {
  font-size: 12px;
  color: var(--subtitle-text);
  margin: 2px 0 0 0;
}

.stats-row {
  display: flex;
  gap: 8px;
}

.stat-pill {
  padding: 5px 12px;
  border-radius: 20px;
  font-size: 12px;
  font-weight: 600;
}

.stat-interviews {
  background: var(--pill-interview-bg);
  color: var(--pill-interview-text);
}

.stat-offers {
  background: var(--pill-offer-bg);
  color: var(--pill-offer-text);
}

.applications {
  padding: 8px 0;
}

.app-row {
  display: grid;
  grid-template-columns: 4px 1fr 1.4fr 56px 90px;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-bottom: 1px solid var(--row-border);
}

.app-row:last-child {
  border-bottom: none;
}

.app-status-bar {
  height: 32px;
  border-radius: 4px;
  width: 4px;
}

.app-offer .app-status-bar { background: var(--bar-offer); }
.app-interview .app-status-bar { background: var(--bar-interview); }
.app-applied .app-status-bar { background: var(--bar-applied); }
.app-rejected .app-status-bar { background: var(--bar-rejected); }

.app-company {
  font-size: 14px;
  font-weight: 600;
  color: var(--company-text);
}

.app-role {
  font-size: 13px;
  color: var(--role-text);
}

.app-date {
  font-size: 12px;
  color: var(--date-text);
  text-align: right;
}

.app-badge {
  padding: 4px 10px;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  text-align: center;
}

.badge-offer { background: var(--badge-offer-bg); color: var(--badge-offer-text); }
.badge-interview { background: var(--badge-interview-bg); color: var(--badge-interview-text); }
.badge-applied { background: var(--badge-applied-bg); color: var(--badge-applied-text); }
.badge-rejected { background: var(--badge-rejected-bg); color: var(--badge-rejected-text); }

.progress-section {
  padding: 12px 20px 16px;
  border-top: 1px solid var(--row-border);
}

.progress-label {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  font-weight: 600;
  color: var(--progress-label-text);
  margin-bottom: 8px;
}

.progress-pct {
  color: var(--progress-pct-text);
}

.progress-track {
  height: 8px;
  background: var(--progress-track-bg);
  border-radius: 100px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  width: 62%;
  background: var(--progress-fill-bg);
  border-radius: 100px;
}
